script.text:
      /* <flatten type="Javascript"> */
function load$ShiftScheduleGrid$(g) {
  g.add_onRender(on$ShiftScheduleGrid$Render);
  g.add_onResponseComplete(on$ShiftScheduleGrid$ResponseComplete);
  g.add_commandEvent(on$ShiftScheduleGrid$ExecuteCommand);
}
function dispose$ShiftScheduleGrid$(g) {
  try {g.remove_commandEvent(on$ShiftScheduleGrid$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$ShiftScheduleGrid$ResponseComplete);} catch (ex) {}
  try {g.remove_onRender(on$ShiftScheduleGrid$Render);} catch (ex) {}
}
function on$ShiftScheduleGrid$Render(sender, eventArgs) {
  var g = eventArgs.grid;
  g._d1 = getDayOfMonth(g._month, g._year, 6), g._d2 = getDayOfMonth(g._month, g._year, 0), a = g._nonWorking.split(',');
  for (var i = 0; i < a.length; i++) {
    var d = parseInt(a[i]);
    if ((Array.indexOf(g._d2, d) == -1) && !isNaN(d)) g._d2.push(d);
  }
  if (g._hiddenFields) {
    var a = g._hiddenFields;
    for (var i = 0; i < a.length; i++) setGridHiddenFields(g, a[i].Fields, a[i].Value);
  }
  for (var i = (g._rowCount ? 1 : 0); i <= g._rowCount; i++) {
    setGridColor(g, g._d1, i, '#4695d6', '#e6edf7');
    setGridColor(g, g._d2, i, '#e6400d', '#e9edf1');
  }
}
function on$ShiftScheduleGrid$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, b = (g._activeRow != -1);
  if (b) g._employeeID = $func.trim(g._getItemValue(g._activeRow, g._getColumnOrder('ma_nv')));
  switch (action) {
    case 'CopyRow':
      if (b) show$Form(g, 'hrShiftScheduleCopyRow');
      break;
    case 'CopyColumn':
      show$Form(g, 'hrShiftScheduleCopyColumn');
      break;
    case 'Truncate':
      show$Form(g, 'hrShiftScheduleTruncate');
      break;
    case 'ImportData':
      show$Form(g, 'hrShiftScheduleImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    default:
      break;
  }
}
function on$ShiftScheduleGrid$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}
function setGridHiddenFields(g, s, v) {
  var a = s.split(',');
  for (var i = 0; i < a.length; i++) g._setColumnVisible(g._getColumnOrder($func.trim(a[i])), !v);
}
function setGridColor(g, a, r, c, b) {
  var id = g.get_id(), k = (r > 0);
  for (var i = 0; i < a.length; i++) {
    $get(id + '_HeaderText_' + (a[i] > 9 ? 'n' + a[i].toString() : 'n0' + a[i].toString())).style.color = c;
    if (k) $get(id + '_gridCell_' + r.toString() + '.' + (a[i] + 4).toString()).style.backgroundColor = b;
  }
}
function getDayOfMonth(m, y, x) {
  var a = [], d = new Date(y, m - 1, 1), day = d.getDay(), v = (x == 0 ? 7 : 6);
  if (day != x) d.setDate(d.getDate() + (v - day));
  a.push(d.getDate());
  while (d) {
    d.setDate(d.getDate() + 7);
    if (d.getMonth() != (m - 1)) return a;
    a.push(d.getDate());
  }
}
function show$Form(g, c) {(!g._denyEdit) ? (g._authorize == 1) ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess")) : $message.show(g._denyMessage);}
/* </flatten> */
      &DowloadScript;

css.text:

div.Edit{background-image:url(../images/Highlight.png);background-repeat:no-repeat;background-position:0 0;}
div.TextEdit{background-image:url(../images/Highlight.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.CopyRow{background-image:url(../images/Shift.png);background-repeat:no-repeat;background-position:0 0;}
div.CopyColumn{background-image:url(../images/Shift.png);background-repeat:no-repeat;background-position:-22px 0;}
div.ImportData{background-image:url(../images/Upload.png);background-repeat:no-repeat;background-position:0 0;}
div.Download{background-image:url(../Images/Download.png);background-repeat:no-repeat;background-position:0 0;}
div.Truncate{background-image:url(../images/command.png);background-repeat:no-repeat;background-position:-44px 0;}
div.TextCopyRow{background-image:url(../images/TextAsterisk.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.TextCopyColumn{background-image:url(../images/TextClone.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.TextTruncate{background-image:url(../images/TextRemove.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.EditOverGreen, div.TextEditOverGreen, div.CopyColumnOverGreen, div.TextCopyColumnOverGreen, div.TextCopyRowOverGreen, div.DownloadOverGreen, div.ImportDataOverGreen, div.CopyRowOverGreen, div.TruncateOverGreen, div.TextTruncateOverGreen{background-position-y:-22px;}
